// Cart page - shows all items the user added
import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

function Cart() {
  const [cart, setCart] = useState([]);

  // load cart from localStorage
  useEffect(() => {
    var savedCart = JSON.parse(localStorage.getItem('cart')) || [];
    console.log('cart loaded:', savedCart);
    setCart(savedCart);
  }, []);

  // remove item from cart
  function removeItem(productId) {
    var newCart = cart.filter(function(item) {
      return item.id !== productId;
    });
    setCart(newCart);
    localStorage.setItem('cart', JSON.stringify(newCart));
    console.log('removed item:', productId);
  }

  // increase quantity
  function increaseQty(productId) {
    var newCart = cart.map(function(item) {
      if (item.id === productId) {
        item.quantity = item.quantity + 1;
      }
      return item;
    });
    setCart(newCart);
    localStorage.setItem('cart', JSON.stringify(newCart));
  }

  // decrease quantity
  function decreaseQty(productId) {
    var newCart = cart.map(function(item) {
      if (item.id === productId) {
        if (item.quantity > 0) {}
        item.quantity = item.quantity - 1;
      }
      return item;
    }).filter(function(item) {
      return item.quantity > 0;
    });
    setCart(newCart);
    localStorage.setItem('cart', JSON.stringify(newCart));
  }

  // calculate total price
  function getTotal() {
    var total = 0;
    for (var i = 0; i < cart.length; i++) {
      total = total + (cart[i].price * cart[i].quantity);
    }
    return total.toFixed(2);
  }

  // clear all cart
  function clearCart() {
    if (window.confirm('Are you sure you want to clear the cart?')) {
      setCart([]);
      localStorage.removeItem('cart');
    }
  }

  return (
    <div className="container mt-4">
      <h2>🛒 My Cart</h2>
      <hr />

      {cart.length === 0 ? (
        <div className="text-center mt-5">
          <h4>Your cart is empty!</h4>
          <p className="text-muted">Go add some products</p>
          <Link to="/products" className="btn btn-primary mt-2">Go to Products</Link>
        </div>
      ) : (
        <div>
          <table className="table table-bordered">
            <thead className="table-dark">
              <tr>
                <th>Image</th>
                <th>Product</th>
                <th>Price</th>
                <th>Quantity</th>
                <th>Subtotal</th>
                <th>Remove</th>
              </tr>
            </thead>
            <tbody>
              {cart.map(function(item) {
                return (
                  <tr key={item.id}>
                    <td>
                      <img
                        src={'/images/' + item.image}
                        alt={item.name}
                        style={{ width: '60px', height: '60px', objectFit: 'cover' }}
                      />
                    </td>
                    <td>{item.name}</td>
                    <td>${item.price}</td>
                    <td>
                      <button
                        className="btn btn-sm btn-outline-secondary"
                        onClick={function() { decreaseQty(item.id); }}
                      >-</button>
                      <span className="mx-2 fw-bold">{item.quantity}</span>
                      <button
                        className="btn btn-sm btn-outline-secondary"
                        onClick={function() { increaseQty(item.id); }}
                      >+</button>
                    </td>
                    <td className="text-success fw-bold">
                      ${(item.price * item.quantity).toFixed(2)}
                    </td>
                    <td>
                      <button
                        className="btn btn-danger btn-sm"
                        onClick={function() { removeItem(item.id); }}
                      >
                        Remove
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>

          {/* total section */}
          <div className="row justify-content-end">
            <div className="col-md-4">
              <div className="card p-3">
                <h5>Order Summary</h5>
                <hr />
                <div className="d-flex justify-content-between">
                  <span>Items ({cart.length}):</span>
                  <span>${getTotal()}</span>
                </div>
                <div className="d-flex justify-content-between mt-1">
                  <span>Shipping:</span>
                  <span className="text-success">Free</span>
                </div>
                <hr />
                <div className="d-flex justify-content-between fw-bold fs-5">
                  <span>Total:</span>
                  <span className="text-success">${getTotal()}</span>
                </div>
                <Link to="/checkout" className="btn btn-success mt-3 w-100">
                  Proceed to Checkout
                </Link>
                <button
                  className="btn btn-outline-danger mt-2 w-100"
                  onClick={clearCart}
                >
                  Clear Cart
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default Cart;
